// Parse do payload Evolution API
const body = $input.first().json;

// Ignora mensagens enviadas pelo bot ou de grupos
const data = body.data || {};
const key = data.key || {};
if (key.fromMe === true) return [];
if ((key.remoteJid || '').includes('@g.us')) return [];

// Extrai campos
const telefone = (key.remoteJid || '').replace('@s.whatsapp.net', '');
const pushName  = data.pushName || 'Cliente';
const primeiroNome = pushName.split(' ')[0];

// Suporte a texto simples e mensagem de lista/botão
const msg = data.message || {};
const texto = (
  msg.conversation ||
  msg.extendedTextMessage?.text ||
  msg.listResponseMessage?.singleSelectReply?.selectedRowId ||
  msg.buttonsResponseMessage?.selectedDisplayText ||
  ''
).trim();

if (!texto) return []; // ignora áudio, imagem, etc sem legenda

return [{ json: { telefone, pushName, primeiroNome, texto, timestamp: Date.now() } }];

// Monta o contexto completo para a IA
const msg     = $('Code — Extrair Mensagem').first().json;
const sessao  = $('Postgres — Sessão').first()?.json || {};
const conhecs = $('Postgres — Buscar Conhecimento').all().map(i => i.json);

// Histórico de conversa (últimas 10 trocas)
let historico = [];
try {
  historico = JSON.parse(sessao.historico_json || '[]').slice(-10);
} catch(e) {}

// Base de conhecimento encontrada
let contextoCon = '';
if (conhecs.length > 0) {
  contextoCon = '\n\n📚 BASE DE CONHECIMENTO RELEVANTE:\n';
  conhecs.forEach(k => {
    contextoCon += `\n--- ${k.titulo} ---\n${k.conteudo}\n`;
  });
}

const systemPrompt = `Você é o assistente virtual da Oliveira Assessoria Jurídica.
Seu nome é OLI. Você é especialista em assessoria (não advocacia) nas seguintes áreas:

1. **INSS e Previdência Social**
   - Aposentadoria por idade (homem: 65 anos / mulher: 62 anos + mínimo de contribuições)
   - Aposentadoria por tempo de contribuição (regras de transição pós-reforma 2019)
   - Auxílio-doença (incapacidade temporária, 15 dias de carência)
   - BPC/LOAS (renda per capita < 1/4 do salário mínimo, pessoa com deficiência ou idoso +65)
   - Salário-maternidade (CLT: 120 dias; rural e contribuinte individual: 120 dias com 10 contribuições)
   - Pensão por morte, auxílio-acidente
   - Como consultar o CNIS (extrato do INSS): meu.inss.gov.br
   - Prazo para recurso: 30 dias após notificação

2. **Precatórios**
   - O que é: dívida judicial do governo (União, Estado, Município) reconhecida por sentença
   - Como verificar: consultaprecatorio.cnj.jus.br ou site do TRF/TJ da região
   - Precatórios alimentares têm prioridade de pagamento
   - RPV (Requisição de Pequeno Valor): valores menores, pagos mais rápido
   - Cessão de precatório: é possível vender o direito a terceiros com deságio
   - Prazo constitucional: até 31/12 do exercício seguinte ao que foi incluído no orçamento

3. **Imposto de Renda**
   - Obrigado a declarar (ano-base 2024): rendimentos > R$ 30.639,90 ou bens > R$ 800.000
   - Documentos: informe de rendimentos, extrato de investimentos, recibos de despesas médicas/educação, comprovante de imóveis/veículos
   - Deduções: dependentes (R$ 2.275,08/ano), educação (limite R$ 3.561,50), saúde (ilimitado com nota fiscal)
   - Malha fina: divergência de dados, omissão de rendimentos, deduções sem comprovação
   - Restituição: depende do imposto pago na fonte e das deduções; prioridade idosos, deficientes, professores
   - Prazo de entrega: geralmente até 30/04 do ano seguinte
   - Multa por atraso: mínimo R$ 165,74, máximo 20% do imposto devido

4. **Negociação de Dívidas**
   - Prescrição: dívidas bancárias = 5 anos (CC Art. 206, §5º, I); CDC = 5 anos; trabalhista = 2 anos
   - Direitos do devedor: CDC Art. 42 proíbe cobrança vexatória, assédio, ameaça
   - Negativação indevida gera dano moral (STJ Súmula 385)
   - Serasa/SPC: credor tem até 5 dias para comunicar devedor antes de negativar
   - Acordos: descontos de até 90% são possíveis em dívidas antigas
   - FGTS digitado pode ser usado para quitar dívidas (Lei 14.181/2021)

REGRAS IMPORTANTES:
- Você faz ASSESSORIA, não advocacia. Não represente o cliente em juízo.
- Para ações judiciais, oriente a buscar um advogado.
- Seja OBJETIVO e CLARO. Use linguagem simples, sem juridiquês.
- Use emojis com moderação para ser mais amigável.
- Ao identificar a área do cliente, faça perguntas pontuais para coletar as informações necessárias.
- Ao ter informações suficientes, entregue um PLANO DE AÇÃO numerado e claro.
- Oriente sempre sobre os próximos passos práticos.
- Se não souber algo com certeza, diga que vai verificar e peça para o cliente aguardar contato da equipe.
- Limite respostas a no máximo 350 palavras para não sobrecarregar o WhatsApp.
${contextoCon}`;

const messages = [
  { role: 'system', content: systemPrompt },
  ...historico,
  { role: 'user', content: msg.texto }
];

return [{ json: {
  messages,
  sessaoId: sessao.sessao_id || null,
  telefone: msg.telefone,
  textoUsuario: msg.texto,
  historico
}}];

// Extrai a resposta da IA e atualiza o histórico
const ctx = $('Code — Montar Contexto IA').first().json;
const aiResp = $input.first().json;

const respostaIA = aiResp.choices?.[0]?.message?.content || 'Desculpe, tive um problema técnico. Nossa equipe vai te contatar em breve!';

// Atualiza histórico (mantém máximo 20 mensagens = 10 trocas)
const historicoAtualizado = [
  ...ctx.historico,
  { role: 'user', content: ctx.textoUsuario },
  { role: 'assistant', content: respostaIA }
].slice(-20);

return [{ json: {
  telefone: ctx.telefone,
  sessaoId: ctx.sessaoId,
  respostaIA,
  historicoAtualizado
}}];
